import re, json
from pathlib import Path
r = Path('/app/gp_rstan.R').read_text(encoding='utf-8', errors='ignore')
# Try to extract stan model code which is often in a string passed to stan_model or exposed via readLines
model_code = None
# Patterns: 'stanmodel <- stan_model(model_code="..."' or 'model_code <- "..."'
pat = re.compile(r"model_code\s*<-\s*(['\"])(.*?)\1", re.DOTALL)
m = pat.search(r)
if m:
    model_code = m.group(2)
# Also check for readLines of a .stan file
if not model_code:
    m2 = re.search(r"readLines\(.*?(['\"])([^'\"]+\.stan)\1\)", r)
    if m2:
        stan_path = m2.group(2)
        p = Path('/app')/stan_path
        if p.exists():
            model_code = p.read_text(encoding='utf-8', errors='ignore')
print('Found model_code' if model_code else 'No model_code found')
# Extract sampling hyperparameters used in rstan::sampling
iter_ = warmup_ = chains_ = thin_ = None
seed_ = None
control = {}
sm_pat = re.search(r"sampling\(.*?iter\s*=\s*(\d+).*?warmup\s*=\s*(\d+).*?chains\s*=\s*(\d+)(.*)\)", r, re.DOTALL)
