    rest = sm_pat.group(4)
    th = re.search(r"thin\s*=\s*(\d+)", rest)
    if th: thin_ = int(th.group(1))
    sd = re.search(r"seed\s*=\s*(\d+)", rest)
    if sd: seed_ = int(sd.group(1))
    ctrl = re.search(r"control\s*=\s*list\(([^)]*)\)", rest)
    if ctrl:
        for k,v in re.findall(r"(adapt_delta|max_treedepth|stepsize|stepsize_jitter)\s*=\s*([0-9.]+)", ctrl.group(1)):
            control[k] = float(v)
print({'iter':iter_, 'warmup':warmup_, 'chains':chains_, 'thin':thin_, 'seed':seed_, 'control':control})
print((model_code or '')[:1000])
