      "keystrokes": "cat > /app/pystan_analysis.py << 'PY'
import json
import numpy as np
import pandas as pd
from pathlib import Path
import stan

data_dir = Path('/app')
train_X = pd.read_csv(data_dir/'train_X.csv', header=None).values
train_y = pd.read_csv(data_dir/'train_y.csv', header=None).values.squeeze()
test_X = pd.read_csv(data_dir/'test_X.csv', header=None).values
meta = json.loads((data_dir/'meta_public.json').read_text())
# Extract dimensions
N, D = train_X.shape
M = test_X.shape[0]
# Stan model code extracted/adapted from R script
# NOTE: This block should match the R's Stan model exactly; if the R script defines a different model,
# replace the following with the exact code. We assume a GP with ARD lengthscale rho (vector[D]),
# alpha (signal std), sigma (noise std), and linear mean beta (vector[D]).
model_code = r""
functions {
  matrix cov_exp_quad_ard(matrix X1, vector rho, real alpha) {
    int N = rows(X1);
    int D = cols(X1);
    matrix[N,N] K;
    for (i in 1:N) {
      for (j in i:N) {
        real sqdist = 0;
        for (d in 1:D) {
          real diff = X1[i,d] - X1[j,d];
          sqdist += (diff*diff) / (rho[d]*rho[d]);
        }
        real kval = square(alpha) * exp(-0.5 * sqdist);
        K[i,j] = kval;
        K[j,i] = kval;
      }
    }
    return K;
  }
}

data {
  int<lower=1> N;
  int<lower=1> D;
  matrix[N,D] X;
  vector[N] y;
}
parameters {
  real<lower=0> alpha;
  real<lower=0> sigma;
  vector<lower=0>[D] rho;
  vector[D] beta;
}
model {
  // Priors: adapt to match R script if specified
  alpha ~ normal(0, 1);
  sigma ~ normal(0, 1);
  rho ~ normal(0.5, 1);
  beta ~ normal(0, 1);
  // Mean function
  vector[N] mu = X * beta;
  // Covariance
  matrix[N,N] K = cov_exp_quad_ard(X, rho, alpha);
  // Add noise
  for (n in 1:N) K[n,n] = K[n,n] + square(sigma);
  y ~ multi_normal(mu, K);
}
"""

# Data for Stan
stan_data = {
    'N': int(N),
    'D': int(D),
    'X': train_X.astype(float),
    'y': train_y.astype(float)
}

posterior = stan.build(model_code, data=stan_data, random_seed=1)
# Hyperparameters: attempt to mirror R script defaults if any; adjust these after inspecting R
num_chains = meta.get('chains', 4) if isinstance(meta, dict) else 4
num_samples = meta.get('iter', 1000) if isinstance(meta, dict) else 1000
num_warmup = meta.get('warmup', 1000) if isinstance(meta, dict) else 1000
fit = posterior.sample(num_chains=num_chains, num_samples=num_samples, num_warmup=num_warmup)

# Helper to compute posterior means across chains and draws
def posterior_mean(arr):
    arr = np.asarray(arr)
    # arr shape: (chains, draws, ...) -> average over first two axes
    if arr.ndim == 2:
        return arr.mean(axis=(0,1))
    elif arr.ndim == 3:
        return arr.mean(axis=(0,1))
    else:
        return arr.mean()

alpha_mean = float(posterior_mean(fit['alpha']))
sigma_mean = float(posterior_mean(fit['sigma']))
rho_mean = posterior_mean(fit['rho']).astype(float)
beta_mean = posterior_mean(fit['beta']).astype(float)

# Save results
pd.Series([alpha_mean]).to_csv(data_dir/'alpha_est.csv', index=False, header=False)
pd.Series([sigma_mean]).to_csv(data_dir/'sigma_est.csv', index=False, header=False)
pd.Series(rho_mean).to_csv(data_dir/'rho_est.csv', index=False, header=False)
pd.Series(beta_mean).to_csv(data_dir/'beta_est.csv', index=False, header=False)
print('Saved estimates to CSV files.')
